args.cypher:
// Find the MiR100 AAS in Hall 4
MATCH (aas:AssetAdministrationShell {idShort: 'MiR100_001'})-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN aas.idShort, aas.id, sm.idShort, sm.id, sc.id AS templateSemanticId

// Check if MiR100_001 has the TechnicalDataAGV submodel (transport robot template)
MATCH (aas:AssetAdministrationShell {idShort: 'MiR100_001'})-[:HAS_SUBMODEL]->(sm:Submodel {idShort: 'TechnicalDataAGV'})-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN aas.idShort, sm.idShort, sc.id AS templateSemanticId

// Check the MiR100 type shell to confirm it's an AGV/transport robot
MATCH (aas:AssetAdministrationShell {idShort: 'MiR100'})-[:HAS_SUBMODEL]->(sm:Submodel {idShort: 'TechnicalDataAGV'})-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN sm.idShort, sc.id AS templateSemanticId

// Verify UR3e_002 derives from UR3e_Type
MATCH (instance:AssetAdministrationShell {idShort: 'UR3e_002'})-[:DERIVED_FROM]->(type:AssetAdministrationShell)
RETURN type.idShort

// Verify CRX10iA_001 derives from CRX10iA_Type
MATCH (instance:AssetAdministrationShell {idShort: 'CRX10iA_001'})-[:DERIVED_FROM]->(type:AssetAdministrationShell)
RETURN type.idShort

MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
WHERE EXISTS {
  MATCH (aas)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_ELEMENT*1..]->(root:SubmodelElement {idShort: 'Location'})
    WHERE EXISTS {
      MATCH (root)-[:HAS_ELEMENT*0..]->(prop:Property)-[:HAS_VALUE]->(ls:LangString)
      WHERE ls.text CONTAINS 'Hall 4' OR ls.text CONTAINS 'Hall4' OR toLower(ls.text) CONTAINS 'hall 4'
    }
}
RETURN aas.idShort AS asset_name, aas.id AS aas_id, asset.globalAssetId, asset.assetKind

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_ELEMENT*]->(p:Property) WHERE p.value = 'Hall 4'
}
RETURN aas.idShort AS aasIdShort, aas.id AS aasId, sm.idShort AS smIdShort, sm.id AS smId
LIMIT 10

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_ELEMENT*]->(p:Property) WHERE p.value CONTAINS 'Hall 4'
}
RETURN aas.idShort, aas.id, sm.idShort, sm.id
LIMIT 10
